import * as React from 'react';
import { Search, Filter, Clock, BookOpen, Star, Plus } from 'lucide-react';
import { Link } from 'react-router-dom';

interface Scenario {
  _id: string;
  title: string;
  description: string;
  practiceArea: string;
  difficulty: 'Beginner' | 'Intermediate' | 'Advanced' | 'Expert';
  estimatedTime: number;
  rating: number;
  reviewCount: number;
  price: number;
  tags: string[];
  status: string;
  createdAt: string;
  updatedAt: string;
  creator: {
    username: string;
  };
}

const ScenarioBrowser: React.FC = () => {
  const [scenarios, setScenarios] = React.useState<Scenario[]>([
    // Actual scenario data based on the PDF content
    {
      _id: '1',
      title: 'The Inventory That Changed Everything',
      description: 'A warehouse supervisor is wrongfully accused of theft after valuable electronics go missing from his workplace. As his defense attorney, you must investigate the case, interview the client, research relevant laws, and argue for bail in court.',
      practiceArea: 'Criminal Law',
      difficulty: 'Intermediate',
      estimatedTime: 30,
      rating: 4.7,
      reviewCount: 32,
      price: 0,
      tags: ['bail application', 'client interviewing', 'legal research', 'oral advocacy', 'theft case'],
      status: 'published',
      createdAt: '2025-01-15T10:30:00Z',
      updatedAt: '2025-01-20T14:45:00Z',
      creator: {
        username: 'LegalExpert2025'
      }
    }
  ]);
  const [filteredScenarios, setFilteredScenarios] = React.useState<Scenario[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState('');
  const [searchTerm, setSearchTerm] = React.useState('');
  const [selectedCategory, setSelectedCategory] = React.useState('All');
  const [selectedDifficulty, setSelectedDifficulty] = React.useState('All');

  const categories = ['All', 'Criminal Law', 'Civil Law', 'Corporate Law', 'Family Law', 'Constitutional Law', 'Tax Law', 'Intellectual Property'];
  const difficulties = ['All', 'Beginner', 'Intermediate', 'Advanced', 'Expert'];

  // Simulate loading
  React.useEffect(() => {
    setTimeout(() => {
      setLoading(false);
      setFilteredScenarios(scenarios);
    }, 500);
  }, [scenarios]);

  // Filter scenarios based on search and filters
  React.useEffect(() => {
    let result = [...scenarios];
    
    if (searchTerm) {
      result = result.filter(scenario => 
        scenario.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
        scenario.description.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }
    
    if (selectedCategory !== 'All') {
      result = result.filter(scenario => scenario.practiceArea === selectedCategory);
    }
    
    if (selectedDifficulty !== 'All') {
      result = result.filter(scenario => scenario.difficulty === selectedDifficulty);
    }
    
    setFilteredScenarios(result);
  }, [searchTerm, selectedCategory, selectedDifficulty, scenarios]);

  const formatDuration = (minutes: number) => {
    if (minutes < 60) {
      return `${minutes} min`;
    } else {
      const hours = Math.floor(minutes / 60);
      const mins = minutes % 60;
      return mins > 0 ? `${hours}h ${mins}m` : `${hours}h`;
    }
  };

  const getDifficultyColor = (difficulty: string) => {
    switch (difficulty) {
      case 'Beginner': return 'bg-green-100 text-green-800';
      case 'Intermediate': return 'bg-blue-100 text-blue-800';
      case 'Advanced': return 'bg-yellow-100 text-yellow-800';
      case 'Expert': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-12">
        <div className="text-center">
          <div className="inline-block animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
          <p className="text-gray-600">Loading scenarios...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container mx-auto px-4 py-12">
        <div className="text-center py-12">
          <div className="bg-red-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
            <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
            </svg>
          </div>
          <h3 className="text-xl font-bold text-gray-900 mb-2">Error Loading Scenarios</h3>
          <p className="text-gray-600 mb-4">{error}</p>
          <button 
            className="bg-indigo-600 text-white px-6 py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium"
            onClick={() => window.location.reload()}
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-12">
      <div className="text-center max-w-3xl mx-auto mb-12">
        <h1 className="text-3xl md:text-4xl font-bold text-gray-900 mb-6">
          Legal Scenario Library
        </h1>
        <p className="text-xl text-gray-600">
          Practice with hundreds of realistic legal scenarios designed by experienced practitioners
        </p>
        <div className="mt-6">
          <Link to="/create-scenario">
            <button className="inline-flex items-center bg-gradient-to-r from-indigo-600 to-purple-600 text-white px-6 py-3 rounded-lg hover:from-indigo-700 hover:to-purple-700 transition duration-300 font-medium">
              <Plus className="w-5 h-5 mr-2" />
              Create Custom Scenario
            </button>
          </Link>
          <p className="mt-3 text-sm text-gray-500">
            Premium feature: 1000 points for 5 custom scenarios per month
          </p>
        </div>
      </div>

      {/* Search and Filters */}
      <div className="bg-white rounded-xl shadow-sm p-6 mb-8">
        <div className="flex flex-col md:flex-row gap-4 mb-6">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
            <input
              type="text"
              placeholder="Search scenarios..."
              className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button className="bg-indigo-600 text-white px-6 py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium flex items-center">
            <Filter className="w-5 h-5 mr-2" />
            Advanced Filters
          </button>
        </div>

        <div className="flex flex-wrap gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Category</label>
            <select 
              className="border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent bg-white shadow-sm hover:shadow-md transition-shadow duration-300"
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
            >
              {categories.map(category => (
                <option key={category} value={category}>{category}</option>
              ))}
            </select>
          </div>
          
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Difficulty</label>
            <select 
              className="border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent bg-white shadow-sm hover:shadow-md transition-shadow duration-300"
              value={selectedDifficulty}
              onChange={(e) => setSelectedDifficulty(e.target.value)}
            >
              {difficulties.map(difficulty => (
                <option key={difficulty} value={difficulty}>{difficulty}</option>
              ))}
            </select>
          </div>
          
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Access Type</label>
            <select className="border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent bg-white shadow-sm hover:shadow-md transition-shadow duration-300">
              <option>All Types</option>
              <option>Free Only</option>
              <option>Premium Only</option>
            </select>
          </div>
        </div>
      </div>

      {/* Scenario Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
        {filteredScenarios.map(scenario => (
          <Link to={`/scenarios/${scenario._id}`} key={scenario._id} className="block">
            <div className="bg-white rounded-xl shadow-sm hover:shadow-md transition-shadow duration-300 overflow-hidden border border-gray-100">
              <div className="p-6">
                <div className="flex justify-between items-start mb-3">
                  <h3 className="text-lg font-bold text-gray-900 line-clamp-2">{scenario.title}</h3>
                  {scenario.price === 0 ? (
                    <span className="bg-green-100 text-green-800 text-xs font-medium px-2 py-1 rounded">FREE</span>
                  ) : (
                    <span className="bg-purple-100 text-purple-800 text-xs font-medium px-2 py-1 rounded">{scenario.price} pts</span>
                  )}
                </div>
                
                <p className="text-gray-600 text-sm mb-4 line-clamp-3">{scenario.description}</p>
                
                <div className="flex flex-wrap items-center gap-3 text-sm text-gray-500 mb-4">
                  <div className="flex items-center">
                    <BookOpen className="w-4 h-4 mr-1" />
                    {scenario.practiceArea}
                  </div>
                  <div className="flex items-center">
                    <Clock className="w-4 h-4 mr-1" />
                    {formatDuration(scenario.estimatedTime)}
                  </div>
                </div>
                
                <div className="flex flex-wrap items-center justify-between">
                  <span className={`px-2 py-1 rounded-full text-xs font-medium ${getDifficultyColor(scenario.difficulty)}`}>
                    {scenario.difficulty}
                  </span>
                  
                  <div className="flex items-center">
                    <Star className="w-4 h-4 text-yellow-400 mr-1" />
                    <span className="text-sm text-gray-600">{scenario.rating} ({scenario.reviewCount})</span>
                  </div>
                </div>
                
                <div className="mt-4 pt-4 border-t border-gray-100">
                  <div className="flex items-center justify-between">
                    <span className="text-xs text-gray-500">By {scenario.creator.username}</span>
                    <button className="text-indigo-600 hover:text-indigo-800 text-sm font-medium flex items-center">
                      View Details
                      <svg className="w-4 h-4 ml-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"></path>
                      </svg>
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </Link>
        ))}
      </div>

      {/* Coming Soon Message */}
      <div className="text-center py-12">
        <div className="bg-gray-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
          <Search className="w-8 h-8 text-gray-400" />
        </div>
        <h3 className="text-xl font-bold text-gray-900 mb-2">More Scenarios Coming Soon</h3>
        <p className="text-gray-600">We're working on creating new legal scenarios for you. Check back soon for updates!</p>
      </div>
    </div>
  );
};

export default ScenarioBrowser;
